//dilate - Outputs the maximum of the center and neighbors
void main()
{

	vec4 tmpSample = vec4(0.0);
	vec4 minSamp = texture(sTD2DInputs[0],vUV.st);
	vec2 res = uTD2DInfos[0].res.xy;

	for (int i = 0; i < int(arraySize); i++) {
		tmpSample = texture(sTD2DInputs[0],
		vec2(vUV.s + res.x * texelFetch(neighbors,i).x,
		     vUV.t + res.y * texelFetch(neighbors,i).y));
		minSamp = min(minSamp, tmpSample);
   }

   fragColor = minSamp;
}
